const ContactForm={init:function(){const t=document.getElementById("contactForm");t&&t.addEventListener("submit",e=>{e.preventDefault();const n=t.name.value.trim(),o=t.email.value.trim(),i=t.message.value.trim();if(!n||!o||!i)return void window.AppUI?.toast?.("Fill in all required fields","error");const r=t.querySelector('button[type="submit"]');r&&(r.disabled=!0),window.AppUI?.toast?.("Message sent. Thank you for reaching out.","success"),t.reset(),r&&(r.disabled=!1)})}};window.ContactForm=ContactForm;
